#include<cstdio>
#include<cmath>
#define int long long
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
inline int Min(int x,int y){return x<y?x:y;}
inline int Max(int x,int y){return x>y?x:y;}
inline void Swap(int x,int y){int tmp=x;x=y;y=tmp;}
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int Mod=999911659;
inline int Slide(int a,int *res)
{
	int p=0,tt=sqrt(a);
	rep(1,tt,i){if(a%i==0)res[++p]=i,res[++p]=a/i;}
	return res[p]==res[p-1]?p-1:p;
}
inline int qpow(int a,long long b,int Mod)
{
	int res=1;while(b)
	{
		if(b&1)res=1ll*res*a%Mod;
		a=1ll*a*a%Mod;b=b>>1;
	}return res;
}
const int N=2e7+10; 
long long fac[50010];
inline void exgcd(long long a,long long b,long long &x,long long &y)
{
	long long tmp;
	b?(exgcd(b,a%b,x,y),tmp=x,x=y,y=tmp-a/b*y):(x=1,y=0);
}
void Init(int p){fac[0]=1;rep(1,p,i)fac[i]=fac[i-1]*i%p;}
int C(int n,int m,int p){if(n<m) return 0;int tmp=fac[n]*qpow(fac[m],p-2,p)%p*qpow(fac[n-m],p-2,p)%p;return tmp;;}
inline int qC(int n,int m,int Mod){return (n<m)?0:(n?1ll*qC(n/Mod,m/Mod,Mod)*C(n%Mod,m%Mod,Mod)%Mod:1);}
int qwq[1000005],ans[5],mod[5];
signed main()
{
   
	int n=read(),g=read(),m=Slide(n,qwq);
	if(g%(Mod)==0){puts("0");return 0;}
	mod[1]=2;mod[2]=3;mod[3]=4679;mod[4]=35617;long long M=2*3*4679*35617;
	rep(1,4,j){Init(mod[j]);rep(1,m,i)ans[j]=(ans[j]+qC(n,qwq[i],mod[j]))%mod[j];}
	long long res=0;rep(1,4,i)
	{
		long long m=M/mod[i],x=0,y=0;exgcd(m,mod[i],x,y);
		res+=ans[i]*m*(x<0?x+mod[i]:x);
	}
	printf("%lld\n",qpow(g,res,Mod));
}
